3861	  \lean{AlgebraicGeometry.Scheme.Modules.fromTildeΓ}
3862	  \mathlibok
3863	  \textit{Provided by Mathlib.}
3864	  For a ring \(R\) and an \(\mathcal{O}_{\operatorname{Spec} R}\)-module \(\mathcal{F}\), the
3865	  tilde--\(\Gamma\) counit
3866	  \(\operatorname{fromTilde\Gamma} : \widetilde{\Gamma(\operatorname{Spec} R, \mathcal{F})} \to
3867	  \mathcal{F}\) is the natural morphism of sheaves of modules whose component over a distinguished
3868	  open \(D(f)\) is the localization lift \(\operatorname{IsLocalizedModule.lift}\) of the
3869	  section-restriction map \(\Gamma(\operatorname{Spec} R, \mathcal{F}) \to \Gamma(D(f), \mathcal{F})\)
3870	  along the structure-sheaf localization \(\widetilde{(-)}.\operatorname{toOpen}\) (the latter
3871	  exhibiting \(\Gamma(D(f), \widetilde{M}) = M_f\) as a localization at the powers of \(f\)).
3872	\end{lemma}
3873	
3874	\begin{lemma}[Criterion for the counit to be an isomorphism]
3875	  \label{lem:isIso_fromTildeGamma_iff_mathlib}
3876	  \lean{AlgebraicGeometry.isIso_fromTildeΓ_iff}
3877	  \mathlibok
3878	  \textit{Provided by Mathlib.}
3879	  For an \(\mathcal{O}_{\operatorname{Spec} R}\)-module \(\mathcal{F}\), the counit
3880	  \(\operatorname{fromTilde\Gamma}\) is an isomorphism if and only if \(\mathcal{F}\) lies in the
3881	  essential image of the tilde functor \(M \mapsto \widetilde{M}\); equivalently
3882	  \(\mathcal{F} \cong \widetilde{M}\) for some \(R\)-module \(M\).
3883	\end{lemma}
3884	
3885	\begin{lemma}[The forgetful functor reflects isomorphisms]
3886	  \label{lem:forget_reflectsIso_mathlib}
3887	  \lean{SheafOfModules.fullyFaithfulForget}
3888	  \mathlibok
3889	  \textit{Provided by Mathlib.}
3890	  The forgetful functor \(\operatorname{forget}\) from sheaves of \(\mathcal{O}_X\)-modules to the
3891	  underlying sheaves of abelian groups is fully faithful, hence reflects isomorphisms; the same holds
3892	  for \(\operatorname{toSheaf}\). Consequently a morphism of sheaves of modules is an isomorphism as
3893	  soon as its underlying morphism of sheaves of abelian groups is, and — since a morphism of sheaves
3894	  which is an isomorphism on every member of a basis of the topology is an isomorphism — it suffices
3895	  to check \(\operatorname{fromTilde\Gamma}\) on the basis of distinguished opens \(\{D(f)\}\).
3896	\end{lemma}
